private expand(item: NavigationItem): void {
  // Add item to the expanded items list
  this._expandedItems.update(() => {
    return [...(this.actualExpandedItems() ?? []), {...item, isExpanded: true}];
  });

  // No need to update the level here, this is handled by linkedSignal already
}

buildTableOfContent(docElement: Element): void {
  const headings = this.getHeadings(docElement);

  const tocList: TableOfContentsItem[] = headings.map((heading) => ({
    id: heading.id,
    level: heading.tagName.toLowerCase() as TableOfContentsLevel,
    title: this.getHeadingTitle(heading),
  }));

  this.tableOfContentItems.set(tocList);
}

export function handleHrefClickEventWithRouter(e: Event, router: Router, relativeUrl: string) {
  const pointerEvent = e as PointerEvent;
  if (
    pointerEvent.ctrlKey ||
    pointerEvent.shiftKey ||
    pointerEvent.altKey ||
    pointerEvent.metaKey
  ) {
    return;
  }

  e.preventDefault();
  router.navigateByUrl(relativeUrl);
}

export function formatErrorEventForAnalytics(event: ErrorEvent): string {
  const {message, filename, colno, lineno, error} = event;

  if (error instanceof Error) {
    return formatErrorForAnalytics(error);
  }

  return `${stripErrorMessagePrefix(message)}\n${filename}:` + `${lineno || '?'}:${colno || '?'}`;
}

private listenToDiagnosticsChange(): void {
  this.errors$.subscribe((diagnostics) => {
    if (this.nodeRuntimeState.loadingStep() !== LoadingStep.READY) {
      return;
    }
    this.errors.set(diagnostics);
    this.displayErrorsBox.set(diagnostics.length > 0);
  });
}

function defineTypes(request: ActionMessage<DefineTypesRequest>): void {
  if (!env?.sys || !request.data?.length) return;

  for (const {path, content} of request.data) {
    updateOrCreateFile(env, path, content);
  }

  cachedTypingFiles = request.data ?? [];
}

constructor() {
  if (!isPlatformBrowser(this.platformId)) {
    return;
  }

  const ref = afterRenderEffect({
    read: () => {
      const container = this.editorContainer()?.nativeElement;
      if (!container) {
        return;
      }
      this.setResizeObserver(container);
      ref.destroy();
    },
  });
}

