export function injectEmbeddedTutorialManager(injector: EnvironmentInjector) {
  return runInInjectionContext(injector, () =>
    injectAsync(() =>
      import('./embedded-tutorial-manager.service').then((c) => c.EmbeddedTutorialManager),
    )(),
  );
}

setStatus(status: number): void {
  this.form.status().value.update((previousStatus) => {
    if (this.isStatusSelected(status)) {
      return previousStatus & ~status; // Clear the bit
    } else {
      return previousStatus | status; // Set the bit
    }
  });
}

