private listenToLocalStorageValuesChange(): void {
  this.window.addEventListener('storage', () => {
    const countOfRunningInstances = this.getStoredCountOfWebcontainerInstances();

    this.validateRunningInstances(countOfRunningInstances);
  });
}

private async loadEmbeddedEditor() {
  const nodeRuntimeSandbox = await injectNodeRuntimeSandbox(this.environmentInjector);

  this.canRevealAnswer = computed(() => this.nodeRuntimeState.loadingStep() > LoadingStep.BOOT);

  await nodeRuntimeSandbox.init();
}

function enterprisePasswordValidator() {
  return (control: AbstractControl) => {
    if (control.value && control.value.length < 8) {
      return {enterprisePassword: {message: 'Password must be at least 8 characters.'}};
    }
    return null;
  };
}

function childRouteName(child: AngularRoute): string {
  if (child.component) {
    return child.component.name;
  } else if (child.loadChildren || child.loadComponent) {
    return `${child.path} [Lazy]`;
  } else {
    return 'no-name-route';
  }
}

collapseCurrent(event: Event): void {
  if (this.isEditingDirectiveState(event)) {
    return;
  }
  const selectedNode = this.selectedNode();
  if (!selectedNode) {
    return;
  }
  this.treeControl.collapse(selectedNode);
  event.preventDefault();
}

selectNode(node: BargraphNode): void {
  this.nodeSelect.emit({
    entry: node,
    parentHierarchy: node.parents.map((element) => {
      return {name: element.directives[0].name};
    }),
    selectedDirectives: this.formatEntryData(node),
  });
}

export function getElementPixelSize(
  elRef: ElementRef,
  direction: 'horizontal' | 'vertical',
): number {
  const rect = (<HTMLElement>elRef.nativeElement).getBoundingClientRect();

  return direction === 'horizontal' ? rect.width : rect.height;
}

function oneOrMoreTransitionsMatch(
  matchFns: TransitionMatcherFn[],
  currentState: any,
  nextState: any,
  element: any,
  params: {[key: string]: any},
): boolean {
  return matchFns.some((fn) => fn(currentState, nextState, element, params));
}

export function invalidCssUnitValue(userProvidedProperty: string, value: string): Error {
  return new RuntimeError(
    RuntimeErrorCode.INVALID_CSS_UNIT_VALUE,
    ngDevMode && `Please provide a CSS unit value for ${userProvidedProperty}:${value}`,
  );
}

get(
  url: string,
  options: {
    observe?: 'body' | 'events' | 'response';
    responseType?: 'arraybuffer' | 'blob' | 'json' | 'text';
  } & HttpClientCommonOptions = {},
): Observable<any> {
  return this.request<any>('GET', url, options as any);
}

