export function mainXi18n(
  args: string[],
  consoleError: (msg: string) => void = console.error,
): number {
  const config = readXi18nCommandLineAndConfiguration(args);
  return main(args, consoleError, config, undefined, undefined, undefined);
}

function isWithinExpression(node: ts.Node, expr: ts.Expression): boolean {
  let current: ts.Node | undefined = node;
  while (current !== undefined) {
    if (current === expr) {
      return true;
    }
    current = current.parent;
  }
  return false;
}

export function validateAndRewriteCoreSymbol(name: string): string {
  if (!CORE_SUPPORTED_SYMBOLS.has(name)) {
    throw new Error(`Importing unexpected symbol ${name} while compiling ${CORE_MODULE}`);
  }
  return CORE_SUPPORTED_SYMBOLS.get(name)!;
}

getNgModuleMetadata(node: Reference<ClassDeclaration<ts.Declaration>>): NgModuleMeta | null {
  for (const reader of this.readers) {
    const meta = reader.getNgModuleMetadata(node);
    if (meta !== null) {
      return meta;
    }
  }
  return null;
}

export function isDecoratorIdentifier(exp: ts.Expression): exp is DecoratorIdentifier {
  return (
    ts.isIdentifier(exp) ||
    (ts.isPropertyAccessExpression(exp) &&
      ts.isIdentifier(exp.expression) &&
      ts.isIdentifier(exp.name))
  );
}
